{
  "name": "DashLib AI",
  "description": "A comprehensive library of 50+ dashboard templates with AI-powered recommendations and code generation."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Template {
  id: string;
  category: DashboardCategory;
  title: string;
  purpose: string;
  refreshRate: string;
  dataSources: string[];
  metrics: string[];
  visualizations: string[];
  notes: string;
  alertThreshold?: string;
  variants?: string[];
}

export enum DashboardCategory {
  SaaSFinancial = "SaaS Financial",
  ProductUsage = "Product & Usage",
  AIOps = "AI/LLM Operations",
  MarketingSales = "Marketing & Sales",
  TeamOps = "Team & Operations",
  EnterpriseGov = "Enterprise & Governance"
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

import { GoogleGenAI } from "@google/genai";
import { Template } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateDashboardCode = async (template: Template): Promise<string> => {
  const prompt = `
    Act as a Senior React Engineer. 
    Generate a complete, functional React component for a "${template.title}" dashboard.

    Requirements:
    1. Use Tailwind CSS for styling. Make it look professional, modern, and clean (SaaS style).
    2. Use 'recharts' for the visualizations mentioned: ${template.visualizations.join(', ')}.
    3. Include mock data within the component so it renders immediately.
    4. Metrics to display: ${template.metrics.join(', ')}.
    5. The component should be responsive.
    6. Return ONLY the code for the component. Do not include markdown formatting or backticks around the code.
    7. Use Lucide-React for icons if needed.

    Context:
    Purpose: ${template.purpose}
    Notes: ${template.notes}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } 
      }
    });

    return response.text?.trim() || "Error generating code.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "// Error generating dashboard code. Please check your API Key.";
  }
};

export const getAIRecommendation = async (query: string, templates: Template[]): Promise<string> => {
  const templateContext = templates.map(t => `- ${t.title} (${t.category}): ${t.purpose}`).join('\n');

  const prompt = `
    You are a Data Operations Expert. A user is asking for dashboard advice.

    User Query: "${query}"

    Available Templates in Library:
    ${templateContext}

    Task:
    1. Recommend the 1-3 most relevant templates from the list.
    2. Explain why they fit the user's needs.
    3. Keep the response concise and helpful.
    4. If no template fits perfectly, suggest a combination or a variant.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text?.trim() || "I couldn't generate a recommendation at this time.";
  } catch (error) {
    console.error("Gemini Advisor Error:", error);
    return "Sorry, I'm having trouble connecting to the AI advisor right now.";
  }
};

import React from 'react';
import { Template } from '../types';
import { BarChart3, Activity, PieChart, Users, Lock, Zap, ArrowRight } from 'lucide-react';

interface TemplateCardProps {
  template: Template;
  onClick: (template: Template) => void;
}

const getIcon = (category: string) => {
  switch (category) {
    case 'SaaS Financial': return <BarChart3 className="w-5 h-5 text-indigo-600" />;
    case 'Product & Usage': return <Activity className="w-5 h-5 text-emerald-600" />;
    case 'AI/LLM Operations': return <Zap className="w-5 h-5 text-purple-600" />;
    case 'Marketing & Sales': return <PieChart className="w-5 h-5 text-orange-600" />;
    case 'Team & Operations': return <Users className="w-5 h-5 text-blue-600" />;
    case 'Enterprise & Governance': return <Lock className="w-5 h-5 text-slate-600" />;
    default: return <BarChart3 className="w-5 h-5" />;
  }
};

const TemplateCard: React.FC<TemplateCardProps> = ({ template, onClick }) => {
  return (
    <div 
      onClick={() => onClick(template)}
      className="group bg-white border border-slate-200 rounded-xl p-6 hover:shadow-lg transition-all duration-200 cursor-pointer flex flex-col h-full"
    >
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-slate-50 border border-slate-100">
          {getIcon(template.category)}
          <span className="text-xs font-semibold text-slate-600 uppercase tracking-wider">{template.category.split(' ')[0]}</span>
        </div>
        <span className="text-xs text-slate-400">{template.refreshRate}</span>
      </div>

      <h3 className="text-lg font-bold text-slate-900 mb-2 group-hover:text-indigo-600 transition-colors">
        {template.title}
      </h3>

      <p className="text-sm text-slate-600 mb-6 flex-grow line-clamp-3">
        {template.purpose}
      </p>

      <div className="flex items-center text-indigo-600 font-medium text-sm mt-auto">
        View Template <ArrowRight className="w-4 h-4 ml-1 group-hover:translate-x-1 transition-transform" />
      </div>
    </div>
  );
};

export default TemplateCard;

import React, { useState } from 'react';
import { Template } from '../types';
import { X, Code, Check, Database, LineChart, AlertTriangle, FileText, Loader2, Copy } from 'lucide-react';
import { generateDashboardCode } from '../services/geminiService';

interface TemplateModalProps {
  template: Template;
  onClose: () => void;
}

const TemplateModal: React.FC<TemplateModalProps> = ({ template, onClose }) => {
  const [activeTab, setActiveTab] = useState<'details' | 'code'>('details');
  const [generatedCode, setGeneratedCode] = useState<string>('');
  const [isLoading, setIsLoading] = useState(false);

  const handleGenerateCode = async () => {
    setActiveTab('code');
    if (!generatedCode) {
      setIsLoading(true);
      const code = await generateDashboardCode(template);
      // Strip markdown code blocks if present
      const cleanCode = code.replace(/```tsx|```typescript|```javascript|```/g, "");
      setGeneratedCode(cleanCode);
      setIsLoading(false);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(generatedCode);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden">

        {/* Header */}
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-white shrink-0">
          <div>
            <div className="text-sm font-medium text-indigo-600 mb-1">{template.category}</div>
            <h2 className="text-2xl font-bold text-slate-900">{template.title}</h2>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-slate-100 shrink-0">
          <button 
            onClick={() => setActiveTab('details')}
            className={`flex-1 py-4 text-sm font-medium text-center border-b-2 transition-colors ${activeTab === 'details' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            Specification
          </button>
          <button 
            onClick={handleGenerateCode}
            className={`flex-1 py-4 text-sm font-medium text-center border-b-2 transition-colors flex items-center justify-center gap-2 ${activeTab === 'code' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <Code className="w-4 h-4" />
            Generate React Code
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 bg-slate-50">
          {activeTab === 'details' ? (
            <div className="space-y-8">
              {/* Overview */}
              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                <h3 className="text-lg font-bold text-slate-900 mb-4 flex items-center gap-2">
                  <FileText className="w-5 h-5 text-slate-400" />
                  Purpose & Strategy
                </h3>
                <p className="text-slate-600 leading-relaxed mb-4">{template.purpose}</p>
                <div className="grid grid-cols-2 gap-4 text-sm">
                  <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                    <span className="block text-slate-400 text-xs uppercase mb-1">Refresh Rate</span>
                    <span className="font-semibold text-slate-800">{template.refreshRate}</span>
                  </div>
                  <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                    <span className="block text-slate-400 text-xs uppercase mb-1">Complexity</span>
                    <span className="font-semibold text-slate-800">Intermediate</span>
                  </div>
                </div>
              </div>

              {/* Data & Metrics */}
              <div className="grid md:grid-cols-2 gap-6">
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                  <h3 className="text-lg font-bold text-slate-900 mb-4 flex items-center gap-2">
                    <Database className="w-5 h-5 text-indigo-500" />
                    Data Sources
                  </h3>
                  <div className="flex flex-wrap gap-2">
                    {template.dataSources.map(ds => (
                      <span key={ds} className="px-3 py-1 bg-indigo-50 text-indigo-700 rounded-full text-sm font-medium">
                        {ds}
                      </span>
                    ))}
                  </div>
                  <h4 className="text-sm font-bold text-slate-900 mt-6 mb-3">Core Metrics</h4>
                  <ul className="space-y-2">
                    {template.metrics.map(metric => (
                      <li key={metric} className="flex items-start gap-2 text-sm text-slate-600">
                        <Check className="w-4 h-4 text-green-500 mt-0.5 shrink-0" />
                        {metric}
                      </li>
                    ))}
                  </ul>
                </div>

                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                  <h3 className="text-lg font-bold text-slate-900 mb-4 flex items-center gap-2">
                    <LineChart className="w-5 h-5 text-emerald-500" />
                    Visualizations
                  </h3>
                  <ul className="space-y-3">
                    {template.visualizations.map((vis, idx) => (
                      <li key={idx} className="flex items-center gap-3 p-3 bg-slate-50 rounded-lg border border-slate-100">
                        <div className="w-2 h-2 rounded-full bg-emerald-400"></div>
                        <span className="text-sm font-medium text-slate-700">{vis}</span>
                      </li>
                    ))}
                  </ul>

                  {template.alertThreshold && (
                    <div className="mt-6 p-4 bg-amber-50 border border-amber-100 rounded-lg">
                      <div className="flex items-center gap-2 text-amber-800 font-semibold text-sm mb-1">
                        <AlertTriangle className="w-4 h-4" />
