const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a bespoke dashboard from a free-form user prompt.
 */
export const generateCustomDashboard = async (userPrompt: string): Promise<string> => {
  const prompt = `
    Act as a World-Class Staff Frontend Engineer.
    USER REQUEST: "${userPrompt}"

    YOUR TASK: Generate a complete, production-ready React component that fulfills this request.

    ARCHITECTURAL STANDARDS (MUST INCLUDE):
    1. PERSISTENT DISMISSIBLE BANNER:
       - Top-level alert banner for critical system notifications (e.g., "Critical: Data Sync Failure").
       - Must be dismissible and include a "View Details" action.

    2. CUSTOMIZABLE ALERTING SYSTEM:
       - Implement a UI section for "Threshold Configurations".
       - Fields: Metric selector, Condition (>, <, =), Value, and Notification Channel (Slack/Email).
       - A "Save Alert Rule" button.

    3. INTERACTIVE DASHBOARD ELEMENTS:
       - Use Lucide-React for high-quality icons.
       - Use Recharts for data visualization (themed for an enterprise dark mode).
       - Implement a "User Role" toggle (Executive, Manager, Engineer) to change view perspectives.

    4. ADVANCED FEATURES (IF RELEVANT TO USER REQUEST):
       - If user asks for AI/LLM: Include an A/B Testing workbench with side-by-side prompt results (GPT-4o vs Claude) and metric comparisons (latency/cost).
       - If user asks for Security: Include a Custom Security Rule Builder.

    TECH STACK:
    - React (functional components, hooks).
    - Tailwind CSS (Slate-950 midnight theme).
    - Recharts & Lucide-React.

    CODE QUALITY:
    - Include full mock data and internal state (useState).
    - PII Masking (e.g., "admin***@company.com").
    - Clean, documented, and modular code.

    Return ONLY the raw React code. No markdown blocks.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
    });
    return response.text?.trim() || "// Error: No code generated.";
  } catch (error) {
    console.error("Gemini Custom CodeGen Error:", error);
    return "// Error generating custom dashboard. Please verify your API Key.";
  }
};

/**
 * Generates a full React component code for a given dashboard template.
 */
export const generateDashboardCode = async (template: Template): Promise<string> => {
  const prompt = `
    Act as a Staff Platform Engineer specialized in high-performance Enterprise Dashboards.
    Generate a complete, functional React component for the "${template.title}" dashboard.

    CRITICAL IMPLEMENTATION RULES:

    1. PERSISTENT DISMISSIBLE BANNER:
       - Every generated dashboard MUST have a Banner at the very top (fixed or top of scroll).
       - It should display a critical alert summary (e.g., "ALERT: ${template.alertThreshold || 'Threshold breached'}").
       - It MUST be dismissible with an 'X' button and include a link to "View Details".
       - This banner should only be visible when an alert is "triggered" (simulate this in state).

    2. CUSTOMIZABLE ALERTING SYSTEM UI:
       - Implement a "Alert Rule Configuration" section.
       - Allow users to select a Metric from: ${template.metrics.join(', ')}.
       - Set Threshold conditions: [Greater Than, Less Than, Equal To].
       - Input a threshold value.
       - Select Notification channels: [Email, Slack, SMS].
       - Include a "Save Rule" button that updates local state.

    3. MODEL PERFORMANCE & A/B TESTING (Specifically for "Model Performance & Cost"):
       - Include an "A/B Testing Workbench" UI section.
       - Allow users to select multiple models from: [GPT-4o, Claude 3.5 Sonnet, Llama 3].
       - Provide a textarea for a custom Prompt.
       - A "Run Simultaneous Test" button.
       - SIDE-BY-SIDE RESULTS: Display model outputs in a multi-column grid.
       - For each result, show: Response Text, Quality Score (1-5), Latency (ms), and calculated Cost ($).
       - Include a Recharts comparison chart for Latency and Cost.

    4. SECURITY CUSTOM RULE BUILDER (Specifically for "Security & Compliance"):
       - Dedicated section for "Define Security Rules".
       - Fields: Metric Select (Failed Logins, Policy Violations, etc.), Condition Select, Value Input.
       - "Save Rule" button that shows a success notification.

    TECH STACK:
    - Framework: React (functional components, hooks).
    - UI: Tailwind CSS (Slate-900 enterprise theme).
    - Charts: Recharts.
    - Icons: Lucide-React.

    MOCK DATA:
    - Include full mock data and internal state (useState) to make the UI interactive and demonstrate the features.
    - Mask all PII (e.g., "user***@enterprise.com").

    Return ONLY the raw React component code. Do not include markdown code blocks or text explanation.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
    });

    return response.text?.trim() || "// Error: No code generated.";
  } catch (error) {
    console.error("Gemini CodeGen Error:", error);
    return "// Error generating dashboard code. Please verify your API Key.";
  }
};

/**
 * Provides an architectural recommendation based on a user's query.
 */
export const getAIRecommendation = async (query: string, templates: Template[]): Promise<string> => {
  const templateContext = templates.map(t => `- ${t.title} (${t.category}): ${t.purpose}`).join('\n');

  const prompt = `
    You are an Enterprise Dashboard Architect. 
    A user is asking how to build a monitoring, testing, or alerting solution.

    User Query: "${query}"

    Library Templates:
    ${templateContext}

    Task:
    1. Recommend the 1-2 most relevant templates.
    2. Specifically mention how they use A/B testing (simultaneous model tests) or the custom alert rule builder to solve the user's need.
    3. Keep it professional, technical, and concise.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text?.trim() || "I couldn't generate a recommendation at this time.";
  } catch (error) {
    console.error("Gemini Advisor Error:", error);
    return "Sorry, I'm having trouble connecting to the AI advisor right now.";
  }
};

