                            <span className="text-[10px] font-mono font-bold text-white w-16 text-right">{val.toFixed(metric.field === 'cost' ? 4 : 0)}{metric.suffix}</span>
                          </div>
                        )
                      })}
                    </div>
                  </div>
                ))}
