const CACHE_NAME = 'dashlib-ai-v3.0';

// Core assets required for the app shell
const STATIC_ASSETS = [
  '/',
  '/index.html',
  '/index.tsx',
  '/manifest.json',
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap'
];

// Regex to match approved CDNs for dynamic caching
const CDN_MATCH = /^https:\/\/(esm\.sh|cdn\.jsdelivr\.net|fonts\.gstatic\.com|i\.pravatar\.cc)/;

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      console.log('[SW] Pre-caching static assets');
      return cache.addAll(STATIC_ASSETS);
    })
  );
  // Activate immediately
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keys) => {
      return Promise.all(
        keys.filter((key) => key !== CACHE_NAME).map((key) => {
          console.log('[SW] Clearing old cache:', key);
          return caches.delete(key);
        })
      );
    })
  );
  // Take control of all clients immediately
  self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  const { request } = event;
  const url = new URL(request.url);

  // 1. Bypass strategy for non-GET and specific API calls
  if (
    request.method !== 'GET' || 
    url.hostname === 'generativelanguage.googleapis.com' || // Gemini API
    url.protocol === 'chrome-extension:' // Browser extensions
  ) {
    return;
  }

  // 2. Stale-While-Revalidate Strategy
  event.respondWith(
    caches.match(request).then((cachedResponse) => {
      // Return cached response immediately if available
      const fetchPromise = fetch(request).then((networkResponse) => {
        // Check if we received a valid response
        if (
          !networkResponse || 
          networkResponse.status !== 200 || 
          networkResponse.type !== 'basic' && networkResponse.type !== 'cors'
        ) {
          return networkResponse;
        }

        // Cache approved CDN assets or own origin assets
        if (url.origin === self.location.origin || CDN_MATCH.test(url.href)) {
          const responseToCache = networkResponse.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(request, responseToCache);
          });
        }
        return networkResponse;
      }).catch((err) => {
        // Network failure, return cached response if we have one, otherwise error
        if (cachedResponse) return cachedResponse;
        console.error('[SW] Fetch failed:', err);
        throw err;
      });

      return cachedResponse || fetchPromise;
    })
  );
});

