import React, { useState } from 'react';
import { ShieldAlert, Plus, Trash2, Bell, CheckCircle2, AlertCircle, ToggleLeft, ToggleRight, X, ArrowRight, Settings2, Play, Activity } from 'lucide-react';
import { SecurityRule } from '../types';
import { usePersistentState } from '../hooks/usePersistentState';

interface SecuritySandboxProps {
  onTriggerAlert?: (templateId: string, message: string, severity: 'critical' | 'warning' | 'info') => void;
  templateId?: string;
}

const METRICS = [
  'Failed Login Attempts',
  'Policy Violations',
  'Data Access Events',
  'Security Incidents',
  'Unauthorized API Requests'
];

const CONDITIONS = [
  'greater than',
  'less than',
  'equal to'
];

const SecuritySandbox: React.FC<SecuritySandboxProps> = ({ onTriggerAlert, templateId }) => {
  const [metric, setMetric] = useState(METRICS[0]);
  const [condition, setCondition] = useState(CONDITIONS[0]);
  const [value, setValue] = useState(10);
  const [rules, setRules] = usePersistentState<SecurityRule[]>('dashlib-security-rules', []);
  const [simulationLog, setSimulationLog] = useState<string[]>([]);

  const addRule = () => {
    const newRule: SecurityRule = {
      id: Math.random().toString(36).substr(2, 9),
      metric,
      condition,
      value,
      enabled: true
    };
    setRules([...rules, newRule]);
    setSimulationLog(prev => [`[System] Added rule: ${metric} ${condition} ${value}`, ...prev]);
  };

  const deleteRule = (id: string) => {
    setRules(rules.filter(r => r.id !== id));
  };

  const toggleRule = (id: string) => {
    setRules(rules.map(r => r.id === id ? { ...r, enabled: !r.enabled } : r));
  };

  const simulateTraffic = () => {
    setSimulationLog(prev => ["[Simulation] Generating random telemetry...", ...prev]);

    // Simulate random metric values
    const simulatedValues: Record<string, number> = {};
    METRICS.forEach(m => {
      simulatedValues[m] = Math.floor(Math.random() * 50); // Random value 0-50
    });

    // Check rules
    const violatedRule = rules.find(r => {
      if (!r.enabled) return false;
      const simVal = simulatedValues[r.metric];
      if (r.condition === 'greater than') return simVal > r.value;
      if (r.condition === 'less than') return simVal < r.value;
      if (r.condition === 'equal to') return simVal === r.value;
      return false;
    });

    if (violatedRule) {
      setTimeout(() => {
        const violationMsg = `Security Policy Triggered: ${violatedRule.metric} (${simulatedValues[violatedRule.metric]}) exceeded threshold.`;

        setSimulationLog(prev => [`[Alert] ${violationMsg}`, ...prev]);

        if (onTriggerAlert) {
          onTriggerAlert(templateId || 'security-compliance', violationMsg, 'critical');
        }
      }, 800);
    } else {
      setTimeout(() => {
        setSimulationLog(prev => [`[Info] Traffic normal. No violations detected.`, ...prev]);
      }, 800);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-10">
      {/* Rule Definition Form */}
      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-xl shadow-slate-100">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-slate-900 rounded-2xl">
              <Settings2 className="w-6 h-6 text-white" />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-900 tracking-tight">Security Policy Builder</h3>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-0.5">Define Custom Governance Thresholds</p>
            </div>
          </div>

          <button 
            onClick={simulateTraffic}
            className="flex items-center gap-2 px-6 py-3 bg-indigo-50 text-indigo-700 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-100 transition-all active:scale-95"
          >
            <Activity className="w-4 h-4" />
            Simulate Traffic
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <div className="flex flex-col gap-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observation Metric</label>
            <select 
              value={metric}
              onChange={(e) => setMetric(e.target.value)}
              className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-4 focus:ring-indigo-100 transition-all cursor-pointer"
            >
              {METRICS.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>

          <div className="flex flex-col gap-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Threshold Condition</label>
            <select 
              value={condition}
              onChange={(e) => setCondition(e.target.value)}
              className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-4 focus:ring-indigo-100 transition-all cursor-pointer"
            >
              {CONDITIONS.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>

          <div className="flex flex-col gap-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Threshold Value</label>
            <input 
              type="number"
              value={value}
              onChange={(e) => setValue(Number(e.target.value))}
              className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-4 focus:ring-indigo-100 transition-all"
            />
          </div>

          <div className="flex items-end">
            <button 
              onClick={addRule}
              className="w-full h-[58px] bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-600 transition-all active:scale-95 shadow-xl shadow-slate-200"
            >
              <Plus className="w-5 h-5" /> Save Rule
            </button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Rules Inventory */}
        <div className="lg:col-span-2 bg-slate-50 border border-slate-200 rounded-[2.5rem] p-8">
          <div className="flex items-center gap-3 mb-8">
            <Bell className="w-5 h-5 text-indigo-600" />
            <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Active Policy Inventory</h4>
          </div>

          {rules.length === 0 ? (
            <div className="py-12 text-center">
              <AlertCircle className="w-12 h-12 text-slate-200 mx-auto mb-4" />
              <p className="text-slate-400 font-bold text-sm italic">No active security policies defined.</p>
            </div>
          ) : (
            <div className="space-y-3">
              {rules.map(rule => (
                <div 
                  key={rule.id}
                  className={`flex items-center justify-between p-5 rounded-3xl border transition-all ${rule.enabled ? 'bg-white border-slate-200 shadow-sm' : 'bg-slate-100 border-slate-200 opacity-60'}`}
                >
                  <div className="flex items-center gap-6">
                    <div className={`p-2 rounded-xl ${rule.enabled ? 'bg-indigo-50 text-indigo-600' : 'bg-slate-200 text-slate-400'}`}>
                      <ShieldAlert className="w-4 h-4" />
                    </div>
                    <div>
                      <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-0.5">Monitoring Strategy</p>
                      <p className="text-sm font-bold text-slate-900">
                        IF <span className="text-indigo-600 font-black">{rule.metric}</span> IS <span className="italic">{rule.condition}</span> <span className="font-mono text-xs bg-slate-100 px-2 py-0.5 rounded-lg border border-slate-200">{rule.value}</span>
                      </p>
                    </div>
                  </div>

                  <div className="flex items-center gap-2">
                    <button 
                      onClick={() => toggleRule(rule.id)}
                      className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"
                    >
                      {rule.enabled ? <ToggleRight className="w-10 h-10 text-indigo-600" /> : <ToggleLeft className="w-10 h-10" />}
                    </button>
                    <button 
                      onClick={() => deleteRule(rule.id)}
                      className="p-3 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Simulation Log */}
        <div className="bg-slate-900 text-slate-300 rounded-[2.5rem] p-8 border border-slate-800 flex flex-col h-full max-h-[500px]">
          <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-6">System Log</h4>
          <div className="flex-1 overflow-y-auto space-y-2 font-mono text-xs">
            {simulationLog.length === 0 && <span className="text-slate-600 italic">Waiting for simulation...</span>}
            {simulationLog.map((log, i) => (
              <div key={i} className="pb-2 border-b border-slate-800/50 last:border-0">
                <span className="text-slate-500 mr-2">[{new Date().toLocaleTimeString()}]</span>
                {log}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SecuritySandbox;

import React, { useState } from 'react';
import { Play, CheckCircle2, Clock, DollarSign, BrainCircuit, BarChart2, MessageSquareText, Check, Loader2 } from 'lucide-react';
import { usePersistentState } from '../hooks/usePersistentState';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface TestResult {
  model: string;
  response: string;
  latency: number;
  cost: number;
  tokens: number;
  quality: number; // 1-10 scale
}

interface ModelSandboxProps {
  onTriggerAlert?: (templateId: string, message: string, severity: 'critical' | 'warning' | 'info') => void;
  templateId?: string;
}

const MODELS = [
  { id: 'GPT-4o', color: '#4f46e5' },
  { id: 'Claude 3.5 Sonnet', color: '#f59e0b' },
  { id: 'Llama 3 (70B)', color: '#10b981' },
  { id: 'Gemini 3 Pro', color: '#06b6d4' }
];

const MOCK_DATA: Record<string, TestResult> = {
  'GPT-4o': { model: 'GPT-4o', response: 'The industrial revolution replaced physical labor with machines, while the AI rise replaces cognitive labor with neural networks.', latency: 420, cost: 0.003, tokens: 142, quality: 9.5 },
  'Claude 3.5 Sonnet': { model: 'Claude 3.5 Sonnet', response: 'AI is similar to the steam engine but for the mind; it scales intelligence where steam scaled power.', latency: 890, cost: 0.008, tokens: 185, quality: 9.8 },
  'Llama 3 (70B)': { model: 'Llama 3 (70B)', response: 'Both represent massive shifts in economic production functions by automating human effort.', latency: 120, cost: 0.0001, tokens: 98, quality: 8.2 },
  'Gemini 3 Pro': { model: 'Gemini 3 Pro', response: 'Industrial: Mechanization. AI: Digitization and Autonomy of Reasoning.', latency: 310, cost: 0.002, tokens: 121, quality: 9.2 }
};

const ModelSandbox: React.FC<ModelSandboxProps> = ({ onTriggerAlert, templateId }) => {
  const [prompt, setPrompt] = useState('Compare the industrial revolution with the rise of AI.');
  const [selectedModels, setSelectedModels] = useState<string[]>(['GPT-4o', 'Claude 3.5 Sonnet']);
  const [isTesting, setIsTesting] = useState(false);
  const [results, setResults] = usePersistentState<TestResult[]>('dashlib-ab-results', []);

  const runTest = () => {
    setIsTesting(true);
    // Simulate simultaneous model run
    setTimeout(() => {
      const newResults = selectedModels.map(id => ({
        ...MOCK_DATA[id],
        // Add random jitter to metrics for realism
        latency: Math.floor(MOCK_DATA[id].latency * (0.8 + Math.random() * 0.4)),
      }));
      setResults(newResults);
      setIsTesting(false);

      // Check for performance drift (simulated rule: quality < 8.5)
      const degraded = newResults.find(r => r.quality < 8.5);
      if (degraded && onTriggerAlert) {
         onTriggerAlert(
             templateId || 'llm-performance', 
             `Model Drift Detected: ${degraded.model} quality score fell below baseline (8.5).`, 
             'warning'
         );
      }
    }, 1500);
  };

  const toggleModel = (id: string) => {
    if (selectedModels.includes(id)) {
      setSelectedModels(selectedModels.filter(m => m !== id));
    } else {
      setSelectedModels([...selectedModels, id]);
    }
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-12">
      {/* Control Hub */}
      <div className="bg-white p-8 rounded-[3rem] border border-slate-200 shadow-xl">
        <div className="flex items-center gap-4 mb-10">
          <div className="p-3 bg-indigo-600 rounded-2xl">
            <BrainCircuit className="w-6 h-6 text-white" />
          </div>
          <div>
            <h3 className="text-2xl font-black text-slate-900 tracking-tight">A/B Testing Workbench</h3>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Simultaneous Cross-Model Benchmarking</p>
          </div>
        </div>

        <div className="space-y-8">
          <div>
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 mb-4 block">Select Comparison Cohort</label>
            <div className="flex flex-wrap gap-3">
              {MODELS.map(m => (
                <button
                  key={m.id}
                  onClick={() => toggleModel(m.id)}
                  className={`px-6 py-3 rounded-2xl border-2 font-black text-xs uppercase tracking-widest transition-all ${selectedModels.includes(m.id) ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' : 'bg-white text-slate-400 border-slate-100 hover:border-slate-300'}`}
                >
                  {selectedModels.includes(m.id) && <Check className="w-3 h-3 inline mr-2" />}
                  {m.id}
                </button>
              ))}
            </div>
          </div>

          <div className="relative">
             <div className="absolute top-4 left-4 text-slate-300 pointer-events-none">
                <MessageSquareText className="w-5 h-5" />
             </div>
             <textarea 
               value={prompt}
               onChange={(e) => setPrompt(e.target.value)}
               className="w-full h-32 pl-14 pr-6 py-5 bg-slate-50 border border-slate-200 rounded-[2rem] text-sm font-bold focus:ring-4 focus:ring-indigo-100 outline-none transition-all resize-none shadow-inner leading-relaxed"
               placeholder="Enter your system prompt to test across models..."
             />
          </div>

          <button 
            onClick={runTest}
            disabled={isTesting || selectedModels.length === 0}
            className="w-full py-5 bg-slate-900 text-white rounded-[1.5rem] font-black text-sm uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-indigo-600 disabled:opacity-50 transition-all active:scale-95 shadow-2xl shadow-indigo-100"
          >
            {isTesting ? (
              <Loader2 className="w-5 h-5 animate-spin" />
            ) : (
              <>
                <Play className="w-5 h-5 fill-current" />
                Run Parallel Model Test
              </>
            )}
          </button>
        </div>
      </div>

      {/* Side-by-Side Results */}
      {results.length > 0 && (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
          <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
            {results.map((res) => (
              <div key={res.model} className="bg-white p-8 rounded-[3rem] border border-slate-200 shadow-xl flex flex-col group hover:border-indigo-300 transition-all">
                <div className="flex items-center justify-between mb-6">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-2xl bg-slate-100 flex items-center justify-center text-xs font-black text-slate-900">
                      {res.model[0]}
                    </div>
                    <h4 className="font-black text-slate-900 tracking-tight">{res.model}</h4>
                  </div>
                  <div className="flex items-center gap-1.5 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-black border border-emerald-100 uppercase tracking-widest">
                    <CheckCircle2 className="w-3 h-3" /> Integrity Pass
                  </div>
                </div>

                <div className="flex-1 bg-slate-50 p-6 rounded-3xl border border-slate-100 mb-8 max-h-40 overflow-y-auto">
                  <p className="text-sm text-slate-600 font-medium leading-relaxed italic">"{res.response}"</p>
                </div>

                <div className="grid grid-cols-3 gap-3">
                   <div className="bg-white p-4 rounded-2xl border border-slate-100 text-center">
                      <Clock className="w-4 h-4 mx-auto mb-2 text-indigo-400" />
                      <div className="text-xs font-black text-slate-900">{res.latency}ms</div>
                      <div className="text-[9px] text-slate-400 uppercase font-black">Latency</div>
                   </div>
                   <div className="bg-white p-4 rounded-2xl border border-slate-100 text-center">
                      <DollarSign className="w-4 h-4 mx-auto mb-2 text-emerald-400" />
                      <div className="text-xs font-black text-slate-900">${res.cost.toFixed(4)}</div>
                      <div className="text-[9px] text-slate-400 uppercase font-black">Cost</div>
                   </div>
                   <div className="bg-white p-4 rounded-2xl border border-slate-100 text-center">
                      <Zap className="w-4 h-4 mx-auto mb-2 text-amber-400" />
                      <div className="text-xs font-black text-slate-900">{res.tokens}</div>
                      <div className="text-[9px] text-slate-400 uppercase font-black">Tokens</div>
                   </div>
                </div>
              </div>
            ))}
          </div>

          {/* Metric Comparison Visualization */}
          <div className="bg-slate-900 p-10 rounded-[3rem] shadow-2xl border border-slate-800">
            <div className="flex items-center justify-between mb-10">
              <h4 className="text-xl font-black text-white tracking-tight uppercase">Comparative Performance Matrix</h4>
              <BarChart2 className="w-6 h-6 text-indigo-400" />
            </div>

            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={results} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                  <XAxis dataKey="model" stroke="#94a3b8" fontSize={10} tickLine={false} axisLine={false} />
                  <YAxis stroke="#94a3b8" fontSize={10} tickLine={false} axisLine={false} />
                  <Tooltip 
                    contentStyle={{ backgroundColor: '#0f172a', border: 'none', borderRadius: '12px', fontSize: '10px', color: '#fff' }} 
                    itemStyle={{ color: '#fff' }}
                  />
                  <Bar dataKey="latency" name="Latency (ms)" radius={[10, 10, 0, 0]}>
                    {results.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={MODELS.find(m => m.id === entry.model)?.color || '#4f46e5'} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ModelSandbox;

