                      <div className="text-xs font-black text-slate-900">{res.latency}ms</div>
                      <div className="text-[9px] text-slate-400 uppercase font-black">Latency</div>
                   </div>
                   <div className="bg-white p-4 rounded-2xl border border-slate-100 text-center">
                      <DollarSign className="w-4 h-4 mx-auto mb-2 text-emerald-400" />
                      <div className="text-xs font-black text-slate-900">${res.cost.toFixed(4)}</div>
                      <div className="text-[9px] text-slate-400 uppercase font-black">Cost</div>
                   </div>
                   <div className="bg-white p-4 rounded-2xl border border-slate-100 text-center">
                      <Zap className="w-4 h-4 mx-auto mb-2 text-amber-400" />
                      <div className="text-xs font-black text-slate-900">{res.tokens}</div>
                      <div className="text-[9px] text-slate-400 uppercase font-black">Tokens</div>
                   </div>
                </div>
              </div>
            ))}
          </div>

          {/* Metric Comparison Visualization */}
          <div className="bg-slate-900 p-10 rounded-[3rem] shadow-2xl border border-slate-800">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-6">
              <div className="flex items-center gap-3">
                <BarChart2 className="w-6 h-6 text-indigo-400" />
                <div>
                  <h4 className="text-xl font-black text-white tracking-tight uppercase">Performance Matrix</h4>
                  <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Comparative Analysis</p>
                </div>
              </div>

              <div className="flex bg-slate-800 p-1 rounded-xl overflow-x-auto">
                {(Object.keys(metricConfig) as MetricType[]).map((key) => (
                  <button
                    key={key}
                    onClick={() => setActiveMetric(key)}
                    className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${
                      activeMetric === key 
                        ? 'bg-slate-700 text-white shadow-md' 
                        : 'text-slate-500 hover:text-slate-300'
                    }`}
                  >
                    {metricConfig[key].label}
                  </button>
                ))}
              </div>
            </div>

            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={results} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                  <XAxis 
                    dataKey="model" 
                    stroke="#94a3b8" 
                    fontSize={10} 
                    tickLine={false} 
                    axisLine={false} 
                    fontWeight={700}
                  />
                  <YAxis 
                    stroke="#94a3b8" 
                    fontSize={10} 
                    tickLine={false} 
                    axisLine={false} 
                    tickFormatter={(val) => activeMetric === 'cost' ? `$${val}` : val}
                  />
                  <Tooltip 
                    cursor={{ fill: '#1e293b', opacity: 0.4 }}
                    contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px', fontSize: '12px', color: '#fff', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.5)' }} 
                    itemStyle={{ color: '#fff', fontWeight: 600 }}
                    formatter={(val: number) => [activeMetric === 'cost' ? `$${val}` : val, metricConfig[activeMetric].label]}
                  />
                  <Bar 
                    dataKey={activeMetric} 
                    name={metricConfig[activeMetric].label} 
                    radius={[8, 8, 0, 0]}
                    animationDuration={1000}
                  >
                    {results.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={MODELS.find(m => m.id === entry.model)?.color || '#4f46e5'} />
                    ))}
                    <LabelList dataKey={activeMetric} position="top" fill="#94a3b8" fontSize={10} fontWeight={700} formatter={(val: number) => activeMetric === 'cost' ? `$${val}` : val} />
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ModelSandbox;

const CACHE_NAME = 'dashlib-ai-v3.9';

// Core assets to pre-cache on install
const CORE_ASSETS = [
  './',
  './index.html',
  './index.tsx',
  './manifest.json',
  './types.ts',
  './data.ts',
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap',
];

// Icons and heavy assets
const DYNAMIC_ASSETS = [
  'https://cdn.jsdelivr.net/gh/google/material-design-icons/png/action/dashboard/black/192dp.png',
  'https://cdn.jsdelivr.net/gh/google/material-design-icons/png/action/dashboard/black/512dp.png',
  'https://cdn.jsdelivr.net/gh/google/material-design-icons/png/action/view_quilt/black/192dp.png',
  'https://cdn.jsdelivr.net/gh/google/material-design-icons/png/action/code/black/192dp.png',
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      console.log('[PWA] Pre-caching Core App Shell v3.9');
      return cache.addAll([...CORE_ASSETS, ...DYNAMIC_ASSETS]);
    })
  );
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keys) => {
      return Promise.all(
        keys.map((key) => {
          if (key !== CACHE_NAME) {
            console.log('[PWA] Invaliding legacy cache:', key);
            return caches.delete(key);
          }
        })
      );
    })
  );
  self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  const { request } = event;
  const url = new URL(request.url);

  // 1. Navigation Fallback (Network First -> Cache Fallback)
  // This ensures the user gets the latest index.html if online, but works offline.
  if (request.mode === 'navigate') {
    event.respondWith(
      (async () => {
        try {
          const networkResponse = await fetch(request);
          if (networkResponse && networkResponse.status === 200) {
             const cache = await caches.open(CACHE_NAME);
             cache.put(request, networkResponse.clone());
          }
          return networkResponse;
        } catch (error) {
          console.warn('[PWA] Network navigation failed, serving offline fallback.');
          const cache = await caches.open(CACHE_NAME);
          const cachedResponse = await cache.match('./index.html');
          return cachedResponse || Response.error();
        }
      })()
    );
    return;
  }

  // 2. Bypass Strategy for APIs
  // Don't cache Gemini API or other dynamic data endpoints
  if (url.hostname.includes('googleapis.com') || request.method !== 'GET') {
    return;
  }

  // 3. Stale-While-Revalidate Strategy for Assets
  // Returns cache immediately, then updates in background.
  event.respondWith(
    caches.open(CACHE_NAME).then(async (cache) => {
      const cachedResponse = await cache.match(request);

      const fetchPromise = fetch(request).then((networkResponse) => {
        // Cache valid responses. 
        // IMPORTANT: Allow 'cors' type to cache CDN assets (esm.sh, tailwind, etc)
        if (networkResponse && networkResponse.status === 200 && 
           (networkResponse.type === 'basic' || networkResponse.type === 'cors')) {
          cache.put(request, networkResponse.clone());
        }
        return networkResponse;
      }).catch((err) => {
        // Network failure is expected offline; strict SWR pattern handles this by returning cachedResponse
        // console.debug('[PWA] Background fetch failed', err);
      });

      return cachedResponse || fetchPromise;
    })
  );
});
